y1 =     -l1 * cos(t1)
x2 = x1 + l2 * sin(t2)
y2 = y1 - l2 * cos(t2)

OUT[0] <- x1/l1
OUT[1] <- y1/l1
OUT[2] <- x2/(l1 + l2)
OUT[3] <- y2/(l1 + l2)

